prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?messageFlow WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName .
  ?messageFlow tai:belongsTo ?choreo ;
               a bboExt:MessageFlow .

  # MessageFlows are linked to tasks via sourceRef or targetRef (as string IDs)
  # We need to check if the task's ID is referenced by the message flow
  FILTER(STRENDS(STR(?task), ?messageFlow))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?type ?name WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?elem tai:belongsTo ?choreo ;
        a ?type .
  OPTIONAL { ?elem bbo:name ?name . }
}
LIMIT 50

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mf ?source ?target WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?mf tai:belongsTo ?choreo ;
      a bboExt:MessageFlow ;
      bboExt:sourceRef ?source ;
      bboExt:targetRef ?target .
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName (COUNT(?mf) AS ?messageCount) WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .

  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        bbo:id ?taskId .

  ?mf tai:belongsTo ?choreo ;
      a bboExt:MessageFlow ;
      bboExt:sourceRef ?mf_source ;
      bboExt:targetRef ?mf_target .

  # Check if the task ID is referenced by the message flow
  FILTER(?taskId = ?mf_source || ?taskId = ?mf_target)
}
GROUP BY ?taskName
HAVING (COUNT(?mf) > 1)

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName ?mf ?source ?target WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .

  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName ;
        bbo:id ?taskId .

  ?mf tai:belongsTo ?choreo ;
      a bboExt:MessageFlow ;
      bboExt:sourceRef ?source ;
      bboExt:targetRef ?target .

  # Check if the task ID is contained in the source or target string
  FILTER(CONTAINS(?source, ?taskId) || CONTAINS(?target, ?taskId))
}
LIMIT 20

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?mf ?source ?target WHERE {
  ?model a bboExt:Model ;
         tai:originalId "2f572d235e784b838fa0d7d2a56748ab" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .

  ?task tai:belongsTo ?choreo ;
        a bboExt:ChoreographyTask ;
        bbo:name ?taskName .

  ?mf tai:belongsTo ?choreo ;
      a bboExt:MessageFlow ;
      bboExt:sourceRef ?source ;
      bboExt:targetRef ?target .

  # Get the ID of the task from its URI
  BIND(STRAFTER(STR(?task), "sid-") AS ?taskId)

  # Check if the task ID is contained in the source or target string
  FILTER(CONTAINS(?source, ?taskId) || CONTAINS(?target, ?taskId))
}
LIMIT 20
